    let server = Server::new("test");

    // Simulate some requests
    for _ in 0..10 {
        server.handle_request(mock_request("tools/list")).await;
    }

    let stats = server.stats().expect("stats enabled");
    assert_eq\!(stats.total_requests, 10);
    assert\!(stats.avg_latency > Duration::ZERO);
}
```

