 {"id":"bd-2qu","title":"Create ErrorBoundary wrapper for automatic error display","description":"## Purpose and Rationale

Create an ErrorBoundary wrapper that automatically catches and beautifully displays errors throughout FastMCP. This ensures consistent error presentation without manual render calls everywhere.

## Background

Rather than manually calling error rendering at every error site, an ErrorBoundary pattern wraps operations and automatically handles display on failure. This is similar to React's Error Boundaries but for Rust Result types.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/error/boundary.rs

use std::fmt::Display;
use crate::console::FastMcpConsole;
use crate::error::RichErrorRenderer;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;

/// Wraps operations and displays errors beautifully on failure
pub struct ErrorBoundary {
    renderer: RichErrorRenderer,
    console: FastMcpConsole,
    exit_on_error: bool,
    error_count: std::sync::atomic::AtomicUsize,
}

impl ErrorBoundary {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        let console = FastMcpConsole::new_with_theme(theme.clone(), context.clone());
        let renderer = RichErrorRenderer::new(theme, context);

        Self {
            renderer,
            console,
            exit_on_error: false,
            error_count: std::sync::atomic::AtomicUsize::new(0),
        }
    }

    /// Exit process on error (for CLI applications)
    pub fn with_exit_on_error(mut self, exit: bool) -> Self {
        self.exit_on_error = exit;
        self
    }

    /// Wrap a Result, displaying error if Err
    pub fn wrap<T, E: Into<fastmcp::Error>>(&self, result: Result<T, E>) -> Option<T> {
        match result {
            Ok(value) => Some(value),
            Err(e) => {
                let error = e.into();
                self.handle_error(&error);
                None
            }
        }
    }

    /// Wrap with custom context message
    pub fn wrap_with_context<T, E: Into<fastmcp::Error>>(
        &self, 
        result: Result<T, E>,
        context: &str
    ) -> Option<T> {
        match result {
            Ok(value) => Some(value),
            Err(e) => {
                let error = e.into();
                self.console.print(&format!("[dim]Context: {}[/]", context));
                self.handle_error(&error);
                None
            }
        }
    }

    /// Async version for async operations
    pub async fn wrap_async<T, E, F>(&self, future: F) -> Option<T>
    where
        E: Into<fastmcp::Error>,
        F: std::future::Future<Output = Result<T, E>>,
    {
        match future.await {
            Ok(value) => Some(value),
            Err(e) => {
                let error = e.into();
                self.handle_error(&error);
                None
            }
        }
    }

    fn handle_error(&self, error: &fastmcp::Error) {
        self.error_count.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        self.renderer.render(error, &self.console);

        if self.exit_on_error {
            std::process::exit(1);
        }
    }

    /// Get total error count
    pub fn error_count(&self) -> usize {
        self.error_count.load(std::sync::atomic::Ordering::Relaxed)
    }

    /// Check if any errors have occurred
    pub fn has_errors(&self) -> bool {
        self.error_count() > 0
    }
}
