### Convenience Macros

```rust
// crates/fastmcp-console/src/error/macros.rs

/// Try an operation, display error and return None on failure
#[macro_export]
macro_rules! try_display {
    ($boundary:expr, $expr:expr) => {
        match $boundary.wrap($expr) {
            Some(v) => v,
            None => return,
        }
    };
    ($boundary:expr, $expr:expr, $ctx:expr) => {
        match $boundary.wrap_with_context($expr, $ctx) {
            Some(v) => v,
            None => return,
        }
    };
}

/// Try an operation, display error and return Err on failure
#[macro_export]
macro_rules! try_display_result {
    ($boundary:expr, $expr:expr) => {
        match $expr {
            Ok(v) => v,
            Err(e) => {
                let error = e.into();
                $boundary.handle_error(&error);
                return Err(error);
            }
        }
    };
}
